effect.shader:
//vec2 projectAndClamp(vec2 a, vec2 b) {
//    return clamp(dot(a,b)/dot(b,b),0.0,1.0) * b;
//}
vec2 project(vec2 a, vec2 b) {
    return (dot(a,b)/dot(b,b)) * b;
}

float smoothstepRev(float edge0, float edge1, float x) {
    if(edge0 == edge1) return step(edge0, x);
    else return smoothstep(edge0, edge1, x);
}

void main() {
    float adjStart = start;
    float adjEnd = end;
    float adjFeather = feather/100.0;
    float rad = angle * 0.0174533;
    vec2 v = normalize(vec2(cos(rad),-sin(rad)));
    //vec2 v = (vec4(normalize(vec2(cos(rad),-sin(rad))),0.0,1.0) * acLayerToScreen).xy;
    //float p = length(projectAndClamp(acLayerNorm.st-vec2(0.5,0.5), v))/length(v)+0.5;
    float p = dot(acLayerNorm.st-vec2(0.5,0.5), v)+0.5;

    float p0 = smoothstepRev(adjStart-adjFeather,adjStart,p);
    float p1 = 1. - smoothstepRev(adjEnd,adjEnd+adjFeather,p);
    gl_FragColor = texture2DCv(inputImg.texture,acScreenNorm.st)*p0*p1;
}
